mapper.update:
UPDATE USER_CONSENT
   SET is_active = 'N'
 WHERE user_id = #{userId}
   AND consent_level = #{consentLevel}
   AND is_active = 'Y'

mapper.select:
SELECT *
  FROM USER_CONSENT
 WHERE user_id = #{userId}
   AND consent_level = #{consentLevel}
 ORDER BY created_at DESC, consent_id DESC
